1	import { readFileSync } from "node:fs";
2	import { fileURLToPath } from "node:url";
3	import { quote, claim } from "./claim-office.js";
4	
5	const KNOWN_ITEM_TYPES = new Set([
6	  "sword",
7	  "amulet",
8	  "staff",
9	  "potion",
10	  "rune",
11	  "moonstone",
12	]);
13	
14	function assertKnownItemTypes(items: { type: string }[]): void {
15	  for (const item of items) {
16	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
17	      throw new Error(`Unknown item type: ${item.type}`);
18	    }
19	  }
20	}
21	
22	function countByType(types: string[]): Map<string, number> {
23	  const counts = new Map<string, number>();
24	  for (const type of types) {
25	    counts.set(type, (counts.get(type) ?? 0) + 1);
26	  }
27	  return counts;
28	}
29	
30	function assertDamagesValid(
31	  policyItems: { type: string }[],
32	  damages: { itemType: string; amount: number }[],
33	): void {
34	  const coverageCounts = countByType(policyItems.map((item) => item.type));
35	  for (const damage of damages) {
36	    if (!coverageCounts.has(damage.itemType)) {
37	      throw new Error(
38	        `Claim damages an item not in policy: ${damage.itemType}`,
39	      );
40	    }
41	    if (damage.amount < 0) {
42	      throw new Error(`Negative damage amount: ${damage.amount}`);
43	    }
44	  }
45	  const damageCounts = countByType(damages.map((damage) => damage.itemType));
46	  for (const [itemType, count] of damageCounts) {
47	    if (count > (coverageCounts.get(itemType) ?? 0)) {
48	      throw new Error(`Too many damages for item type: ${itemType}`);
49	    }
50	  }
51	}
52	
53	export function runScenario(scenario: any): { results: unknown[] } {
54	  const results: unknown[] = [];
55	  let quoteCount = 0;
56	  const remainingCaps = new Map<number, number>();
57	  for (const step of scenario.steps) {
58	    if (step.op === "quote") {
59	      assertKnownItemTypes(step.items);
60	      const premium = quote({
61	        customer: {
62	          yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
63	          previousContracts: quoteCount,
64	        },
65	        items: step.items,
66	      });
67	      results.push({ premium });
68	      quoteCount++;
69	    } else if (step.op === "claim") {
70	      const policyStep = scenario.steps[step.policy];
71	      assertDamagesValid(policyStep.items, step.incident.damages);
72	      const { payout, remainingCap = 0 } = claim({
73	        items: policyStep.items,
74	        incident: step.incident,
75	        remainingCap: remainingCaps.get(step.policy),
76	      });
77	      remainingCaps.set(step.policy, remainingCap);
78	      results.push({ payout, remainingCap });
79	    }
80	  }
81	  return { results };
82	}
83	
84	function main(): void {
85	  try {
86	    const scenario = JSON.parse(readFileSync(0, "utf-8"));
87	    const result = runScenario(scenario);
88	    process.stdout.write(JSON.stringify(result));
89	    process.exit(0);
90	  } catch (error) {
91	    process.stderr.write(String(error));
92	    process.exit(1);
93	  }
94	}
95	
96	if (process.argv[1] === fileURLToPath(import.meta.url)) {
97	  main();
98	}
